  5→//! JJK Tally commands - pace modification operations
  6→//!
  7→//! Split into four single-purpose commands:
  8→//! - revise_docket: Update pace docket text
  9→//! - arm: Set state to bridled with warrant
 10→//! - relabel: Rename pace silks
 11→//! - drop: Set state to abandoned
 12→
 13→use std::fmt::Write;
 14→use std::path::PathBuf;
 15→
 16→use crate::jjrf_favor::jjrf_Coronet as Coronet;
 17→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_PaceState as PaceState};
 18→use crate::jjrn_notch::{jjrn_format_heat_message as format_heat_message, jjrn_HeatAction as HeatAction};
 19→
 20→/// Arguments for jjx_revise_docket command
 21→#[derive(clap::Args, Debug)]
 22→pub struct jjrtl_ReviseDocketArgs {
 23→    /// Path to the Gallops JSON file
 24→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 25→    pub file: PathBuf,
 26→
 27→    /// Target Pace identity (Coronet)
 28→    pub coronet: String,
 29→}
 30→
 31→/// Run the revise_docket command
 32→///
 33→/// Updates the docket text for a pace.
 34→pub fn jjrtl_run_revise_docket(args: jjrtl_ReviseDocketArgs, docket: String) -> (i32, String) {
 35→    use crate::jjrg_gallops::jjrg_TallyArgs as LibTallyArgs;
 36→    let mut buf = String::new();
 37→
 38→    // Acquire lock FIRST - fail fast if another operation is in progress
 39→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 40→        Ok(l) => l,
 41→        Err(e) => {
 42→            jjbuf!(buf, "jjx_revise_docket: error: {}", e);
 43→            return (1, buf);
 44→        }
 45→    };
 46→
 47→    let text = docket;
 48→
 49→    let mut gallops = match Gallops::jjrg_load(&args.file) {
 50→        Ok(g) => g,
 51→        Err(e) => {
 52→            jjbuf!(buf, "jjx_revise_docket: error loading Gallops: {}", e);
 53→            return (1, buf);
 54→        }
 55→    };
 56→
 57→    // Get firemark and silks for commit message before we move args
 58→    let coronet_str = args.coronet.clone();
 59→    let (fm, silks) = match Coronet::jjrf_parse(&coronet_str) {
 60→        Ok(c) => {
 61→            let parent_fm = c.jjrf_parent_firemark();
 62→            let silks = gallops.heats.get(&parent_fm.jjrf_display())
 63→                .and_then(|h| h.paces.get(&c.jjrf_display()))
 64→                .and_then(|p| p.tacks.first().map(|t| t.silks.clone()))
 65→                .unwrap_or_else(|| coronet_str.clone());
 66→            (parent_fm, silks)
 67→        }
 68→        Err(e) => {
 69→            jjbuf!(buf, "jjx_revise_docket: error: {}", e);
 70→            return (1, buf);
 71→        }
 72→    };
 73→
 74→    let tally_args = LibTallyArgs {
 75→        coronet: args.coronet,
 76→        state: None,
 77→        direction: None,
 78→        text: Some(text),
 79→        silks: None,
 80→    };
 81→
 82→    match gallops.jjrg_tally(tally_args) {
 83→        Ok(()) => {
 84→            let message = format_heat_message(&fm, HeatAction::Tally, &silks);
 85→
 86→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
 87→                Ok(hash) => {
 88→                    let _ = writeln!(buf, "committed {}", hash);
 89→                    (0, buf)
 90→                }
 91→                Err(e) => {
 92→                    jjbuf!(buf, "jjx_revise_docket: error: {}", e);
 93→                    (1, buf)
 94→                }
 95→            }
 96→        }
 97→        Err(e) => {
 98→            jjbuf!(buf, "jjx_revise_docket: error: {}", e);
 99→            (1, buf)
100→        }
101→    }
102→    // lock released here
103→}
