116→/// Run the arm command
117→///
118→/// Sets pace state to bridled with warrant.
119→/// Creates both a tally commit and a B commit.
120→pub fn jjrtl_run_arm(args: jjrtl_ArmArgs, warrant: String) -> (i32, String) {
121→    use crate::jjrg_gallops::jjrg_TallyArgs as LibTallyArgs;
122→    let mut buf = String::new();
123→
124→    // Acquire lock FIRST - fail fast if another operation is in progress
125→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
126→        Ok(l) => l,
127→        Err(e) => {
128→            jjbuf!(buf, "jjx_arm: error: {}", e);
129→            return (1, buf);
130→        }
131→    };
132→
133→    let mut gallops = match Gallops::jjrg_load(&args.file) {
134→        Ok(g) => g,
135→        Err(e) => {
136→            jjbuf!(buf, "jjx_arm: error loading Gallops: {}", e);
137→            return (1, buf);
138→        }
139→    };
140→
141→    // Get firemark and silks for commit message before we move args
142→    let coronet_str = args.coronet.clone();
143→    let (fm, silks) = match Coronet::jjrf_parse(&coronet_str) {
144→        Ok(c) => {
145→            let parent_fm = c.jjrf_parent_firemark();
146→            let silks = gallops.heats.get(&parent_fm.jjrf_display())
147→                .and_then(|h| h.paces.get(&c.jjrf_display()))
148→                .and_then(|p| p.tacks.first().map(|t| t.silks.clone()))
149→                .unwrap_or_else(|| coronet_str.clone());
150→            (parent_fm, silks)
151→        }
152→        Err(e) => {
153→            jjbuf!(buf, "jjx_arm: error: {}", e);
154→            return (1, buf);
155→        }
156→    };
157→
158→    let tally_args = LibTallyArgs {
159→        coronet: args.coronet,
160→        state: Some(PaceState::Bridled),
161→        direction: Some(warrant.clone()),
162→        text: None,
163→        silks: None,
164→    };
165→
166→    match gallops.jjrg_tally(tally_args) {
167→        Ok(()) => {
168→            let message = format_heat_message(&fm, HeatAction::Tally, &silks);
169→
170→            match crate::jjri_io::jjri_persist(&lock, &gallops, &args.file, &fm, message, 50000) {
171→                Ok(hash) => {
172→                    let _ = writeln!(buf, "committed {}", hash);
173→                }
174→                Err(e) => {
175→                    jjbuf!(buf, "jjx_arm: error: {}", e);
176→                    return (1, buf);
177→                }
178→            }
179→
180→            // Create B commit for bridling
181→            let coronet = match Coronet::jjrf_parse(&coronet_str) {
182→                Ok(c) => c,
183→                Err(e) => {
184→                    jjbuf!(buf, "jjx_arm: error parsing coronet for B commit: {}", e);
185→                    return (1, buf);
186→                }
187→            };
188→
189→            let agent = "arm"; // Agent that bridled the pace
190→
191→            // Build B commit message
192→            use crate::jjrn_notch::jjrn_format_bridle_message;
193→            let b_subject = jjrn_format_bridle_message(&coronet, agent, &silks);
194→            let b_message = format!("{}\n\n{}", b_subject, warrant);
195→
196→            // Create empty B commit using git directly (like chalk markers)
197→            let output = vvc::vvce_git_command(&["commit", "--allow-empty", "-m", &b_message])
198→                .output();
199→
200→            match output {
201→                Ok(result) if result.status.success() => {
202→                    // Get commit hash
203→                    let hash_output = vvc::vvce_git_command(&["rev-parse", "HEAD"])
204→                        .output();
205→
206→                    if let Ok(hash_result) = hash_output {
207→                        if hash_result.status.success() {
208→                            let hash = String::from_utf8_lossy(&hash_result.stdout).trim().to_string();
209→                            let _ = writeln!(buf, "B commit {}", &hash[..8.min(hash.len())]);
210→                        }
211→                    }
212→                }
213→                Ok(result) => {
214→                    let stderr = String::from_utf8_lossy(&result.stderr);
215→                    jjbuf!(buf, "jjx_arm: error creating B commit: {}", stderr);
216→                    return (1, buf);
217→                }
218→                Err(e) => {
219→                    jjbuf!(buf, "jjx_arm: error creating B commit: {}", e);
220→                    return (1, buf);
221→                }
222→            }
223→
224→            jjbuf!(buf, "");
225→            jjbuf!(buf, "Recommended: /jjc-heat-mount {} to execute", fm.jjrf_as_str());
226→            (0, buf)
227→        }
228→        Err(e) => {
229→            jjbuf!(buf, "jjx_arm: error: {}", e);
230→            (1, buf)
231→        }
232→    }
233→    // lock released here
234→}
