  5→//! jjx_retire command - Extract complete Heat data for archival trophy
  6→//!
  7→//! Handles retire operation: write trophy, remove from gallops, delete paddock, commit.
  8→//! Fails fast if gallops file has uncommitted changes.
  9→
 10→use std::fmt::Write;
 11→use std::path::{Path, PathBuf};
 12→
 13→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 14→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_RetireArgs as LibRetireArgs};
 15→use crate::jjrs_steeplechase::{jjrs_ReinArgs as ReinArgs, jjrs_get_entries as get_entries};
 16→use crate::jjrc_core::jjrc_timestamp_date;
 17→use crate::jjrn_notch::{jjrn_format_heat_message, jjrn_HeatAction};
 18→
 19→/// Arguments for jjx_retire command
 20→#[derive(clap::Args, Debug)]
 21→pub struct jjrrt_RetireArgs {
 22→    /// Path to the Gallops JSON file
 23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 24→    pub file: PathBuf,
 25→
 26→    /// Target Heat identity (Firemark)
 27→    pub firemark: String,
 28→
 29→    /// Override size limit for commit guard (bytes)
 30→    #[arg(long)]
 31→    pub size_limit: Option<u64>,
 32→}
 33→
 34→/// Run the retire command
 35→pub fn jjrrt_run_retire(args: jjrrt_RetireArgs) -> (i32, String) {
 36→    let mut buf = String::new();
 37→
 38→    let firemark = match Firemark::jjrf_parse(&args.firemark) {
 39→        Ok(fm) => fm,
 40→        Err(e) => {
 41→            jjbuf!(buf, "jjx_retire: error: {}", e);
 42→            return (1, buf);
 43→        }
 44→    };
 45→
 46→    // Load gallops
 47→    let gallops = match Gallops::jjrg_load(&args.file) {
 48→        Ok(g) => g,
 49→        Err(e) => {
 50→            jjbuf!(buf, "jjx_retire: error loading Gallops: {}", e);
 51→            return (1, buf);
 52→        }
 53→    };
 54→
 55→    // Get steeplechase entries (filtered by firemark identity)
 56→    let rein_args = ReinArgs {
 57→        firemark: args.firemark.clone(),
 58→        limit: 1000,
 59→    };
 60→    let steeplechase = match get_entries(&rein_args) {
 61→        Ok(entries) => entries,
 62→        Err(e) => {
 63→            jjbuf!(buf, "jjx_retire: warning: could not get steeplechase: {}", e);
 64→            Vec::new()
 65→        }
 66→    };
 67→
 68→    // Compute base path from gallops file
 69→    let base_path = args.file.parent()
 70→        .and_then(|p| p.parent())
 71→        .and_then(|p| p.parent())
 72→        .unwrap_or(Path::new("."));
 73→
 74→    // Fail-fast guard: reject if gallops file has uncommitted changes
 75→    let gallops_rel = args.file.to_string_lossy().to_string();
 76→    let status_output = match vvc::vvce_git_command(&["status", "--porcelain", "--", &gallops_rel])
 77→        .output()
 78→    {
 79→        Ok(o) => o,
 80→        Err(e) => {
 81→            jjbuf!(buf, "jjx_retire: error: failed to run git status: {}", e);
 82→            return (1, buf);
 83→        }
 84→    };
 85→    if !status_output.status.success() {
 86→        jjbuf!(buf, "jjx_retire: error: git status failed");
 87→        return (1, buf);
 88→    }
 89→    let status_text = String::from_utf8_lossy(&status_output.stdout);
 90→    if !status_text.trim().is_empty() {
 91→        jjbuf!(buf, "jjx_retire: error: gallops file has uncommitted changes — commit or discard first");
 92→        return (1, buf);
 93→    }
 94→
 95→    let mut gallops = gallops;
 96→
 97→    // Acquire lock FIRST
 98→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
 99→        Ok(l) => l,
100→        Err(e) => {
101→            jjbuf!(buf, "jjx_retire: error: {}", e);
102→            return (1, buf);
103→        }
104→    };
105→
106→    // Execute retire
107→    let retire_args = LibRetireArgs {
108→        firemark: args.firemark.clone(),
109→        today: jjrc_timestamp_date(),
110→    };
111→
112→    let result = match gallops.jjrg_retire(retire_args, base_path, &steeplechase) {
113→        Ok(r) => r,
114→        Err(e) => {
115→            jjbuf!(buf, "jjx_retire: error: {}", e);
116→            return (1, buf);
117→        }
118→    };
119→
120→    // Save gallops
121→    if let Err(e) = gallops.jjrg_save(&args.file) {
122→        jjbuf!(buf, "jjx_retire: error saving Gallops: {}", e);
123→        return (1, buf);
124→    }
125→
126→    // Commit using vvcm_commit with explicit file list
127→    // Files: gallops.json, trophy file (created), paddock file (deleted - git add handles this)
128→    let gallops_path = args.file.to_string_lossy().to_string();
129→    let effective_size_limit = args.size_limit.unwrap_or(200000);
130→    let commit_args = vvc::vvcm_CommitArgs {
131→        files: vec![
132→            gallops_path,
133→            result.trophy_path.clone(),
134→            result.paddock_path.clone(),
135→        ],
136→        message: jjrn_format_heat_message(&firemark, jjrn_HeatAction::Retire, &result.silks),
137→        size_limit: effective_size_limit,
138→        warn_limit: effective_size_limit / 2,
139→    };
140→
141→    match vvc::machine_commit(&lock, &commit_args) {
142→        Ok(hash) => {
143→            jjbuf!(buf, "jjx_retire: committed {}", &hash[..8]);
144→        }
145→        Err(e) => {
146→            jjbuf!(buf, "jjx_retire: error: commit failed: {}", e);
147→            // Rollback: restore gallops and paddock from HEAD, remove trophy
148→            let gp = args.file.to_string_lossy().to_string();
149→            let _ = vvc::vvce_git_command(&["checkout", "HEAD", "--", &gp, &result.paddock_path])
150→                .status();
151→            let _ = vvc::vvce_git_command(&["rm", "-f", "--cached", &result.trophy_path])
152→                .status();
153→            let _ = std::fs::remove_file(&result.trophy_path);
154→            jjbuf!(buf, "jjx_retire: rolled back file changes");
155→            jjbuf!(buf, "jjx_retire: retry with --size-limit <bytes> to override guard");
156→            return (1, buf);
157→        }
158→    }
159→
160→    // Output result
161→    let _ = writeln!(buf, "trophy: {}", result.trophy_path);
162→    let _ = writeln!(buf, "Heat {} retired successfully", result.firemark);
163→
164→    (0, buf)
165→    // lock released here
166→}
