 17→use std::fs;
 18→
 19→/// Arguments for jjx_show command
 20→#[derive(clap::Args, Debug)]
 21→pub struct jjrpd_ParadeArgs {
 22→    /// Path to the Gallops JSON file
 23→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 24→    pub file: std::path::PathBuf,
 25→
 26→    /// Target: Firemark (heat view) or Coronet (pace view). If omitted, uses first racing heat.
 27→    pub target: Option<String>,
 28→
 29→    /// Show paddock and full dockets (heat mode only)
 30→    #[arg(long)]
 31→    pub detail: bool,
 32→
 33→    /// Show only remaining paces (exclude complete/abandoned)
 34→    #[arg(long)]
 35→    pub remaining: bool,
 36→}
 37→
 38→/// Run the show command - display comprehensive Heat status
 39→pub fn jjrpd_run_parade(args: jjrpd_ParadeArgs) -> (i32, String) {
 40→    let mut buf = String::new();
 41→    let gallops = match Gallops::jjrg_load(&args.file) {
 42→        Ok(g) => g,
 43→        Err(e) => {
 44→            jjbuf!(buf, "jjx_show: error: {}", e);
 45→            return (1, buf);
 46→        }
 47→    };
 48→
 49→    // Resolve target: use provided value or auto-select first racing heat
 50→    let target = match args.target {
 51→        Some(t) => t,
 52→        None => {
 53→            // Load gallops to resolve default heat
 54→            match zjjrpd_resolve_default_heat(&gallops) {
 55→                Ok(fm) => fm,
 56→                Err(e) => {
 57→                    jjbuf!(buf, "jjx_show: error: {}", e);
 58→                    return (1, buf);
 59→                }
 60→            }
 61→        }
 62→    };
 63→
 64→    // Determine target type by length
 65→    let target_str = target.strip_prefix('₢').or_else(|| target.strip_prefix('₣')).unwrap_or(&target);
 66→
 67→    if target_str.len() == 5 {
 68→        // Coronet - pace view
 69→        let coronet = match Coronet::jjrf_parse(&target) {
 70→            Ok(c) => c,
 71→            Err(e) => {
 72→                jjbuf!(buf, "jjx_show: error: {}", e);
 73→                return (1, buf);
 74→            }
 75→        };
 76→
 77→        // Extract parent firemark
 78→        let firemark = coronet.jjrf_parent_firemark();
 79→        let heat_key = firemark.jjrf_display();
 80→        let heat = match gallops.heats.get(&heat_key) {
 81→            Some(h) => h,
 82→            None => {
 83→                jjbuf!(buf, "jjx_show: error: Heat '{}' not found", heat_key);
 84→                return (1, buf);
 85→            }
 86→        };
 87→
 88→        // Find pace
 89→        let coronet_key = coronet.jjrf_display();
 90→        let pace = match heat.paces.get(&coronet_key) {
 91→            Some(p) => p,
 92→            None => {
 93→                jjbuf!(buf, "jjx_show: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
 94→                return (1, buf);
 95→            }
 96→        };
 97→
 98→        // Display pace view
 99→        if !pace.tacks.is_empty() {
100→            // Write header with current state from tacks[0]
101→            let current_tack = &pace.tacks[0];
102→            let _ = writeln!(buf, "Pace: {} ({}) [{}]", current_tack.silks, coronet_key, zjjrpd_pace_state_str(&current_tack.state));
103→            let _ = writeln!(buf, "Heat: {}", heat_key);
104→
105→            // Show work files touched by this pace's commits
106→            match jjrq_files_for_pace(firemark.jjrf_as_str(), &coronet_key) {
107→                Ok(files) if !files.is_empty() => {
108→                    let _ = writeln!(buf, "Work files: {}", files.join(", "));
109→                }
110→                _ => {}
111→            }
112→            let _ = writeln!(buf);
113→
114→            if args.detail {
115→                // Detail view: full tack history in reverse order (oldest first)
116→                for (index, tack) in pace.tacks.iter().rev().enumerate() {
117→                    let state_str = zjjrpd_pace_state_str(&tack.state);
118→                    let basis_str = if tack.basis == "0000000" {
119→                        "(no basis)".to_string()
120→                    } else {
121→                        tack.basis.clone()
122→                    };
123→
124→                    let _ = writeln!(buf, "[{}] {} (basis: {})", index, state_str, basis_str);
125→                    let _ = writeln!(buf, "    Silks: {}", tack.silks);
126→                    if let Some(ref direction) = tack.direction {
127→                        let _ = writeln!(buf, "    Warrant: {}", direction);
128→                    }
129→                    let _ = writeln!(buf);
130→                    // Indent docket text
131→                    for line in tack.text.lines() {
132→                        let _ = writeln!(buf, "    {}", line);
133→                    }
134→                    let _ = writeln!(buf);
135→                }
136→            } else {
137→                // Default view: latest tack docket only
138→                if let Some(ref direction) = current_tack.direction {
139→                    let _ = writeln!(buf, "Warrant: {}", direction);
140→                    let _ = writeln!(buf);
141→                }
142→                for line in current_tack.text.lines() {
143→                    let _ = writeln!(buf, "{}", line);
144→                }
145→                let _ = writeln!(buf);
146→            }
147→
148→            // Append files-per-commit bitmap
149→            zjjrpd_write_pace_commits(&mut buf, &firemark, &coronet_key);
150→        }
151→    } else if target_str.len() == 2 {
152→        // Firemark - heat view
153→        let firemark = match Firemark::jjrf_parse(&target) {
154→            Ok(fm) => fm,
155→            Err(e) => {
156→                jjbuf!(buf, "jjx_show: error: {}", e);
157→                return (1, buf);
158→            }
159→        };
160→
161→        let heat_key = firemark.jjrf_display();
162→        let heat = match gallops.heats.get(&heat_key) {
163→            Some(h) => h,
164→            None => {
165→                jjbuf!(buf, "jjx_show: error: Heat '{}' not found", heat_key);
166→                return (1, buf);
167→            }
168→        };
169→
170→        if args.detail {
171→            // Detail view: paddock + all dockets
172→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
173→                Ok(content) => content,
174→                Err(e) => {
175→                    jjbuf!(buf, "jjx_show: error reading paddock file '{}': {}", heat.paddock_file, e);
176→                    return (1, buf);
177→                }
178→            };
179→
180→            let status_str = match heat.status {
181→                HeatStatus::Racing => "racing",
182→                HeatStatus::Stabled => "stabled",
183→                HeatStatus::Retired => "retired",
184→            };
185→
186→            let _ = writeln!(buf, "Heat: {} ({})", heat.silks, heat_key);
187→            let _ = writeln!(buf, "Status: {}", status_str);
188→            let _ = writeln!(buf, "Created: {}", heat.creation_time);
189→            let _ = writeln!(buf);
190→            let _ = writeln!(buf, "## Paddock");
191→            let _ = writeln!(buf);
192→            let _ = writeln!(buf, "{}", paddock_content);
193→            let _ = writeln!(buf);
194→            let _ = writeln!(buf, "## Paces");
195→            let _ = writeln!(buf);
196→
197→            for coronet_key in &heat.order {
198→                if let Some(pace) = heat.paces.get(coronet_key) {
199→                    if let Some(tack) = pace.tacks.first() {
200→                        // Skip complete/abandoned if --remaining
201→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
202→                            continue;
203→                        }
204→                        let state_str = zjjrpd_pace_state_str(&tack.state);
205→                        let _ = writeln!(buf, "### {} ({}) [{}]", tack.silks, coronet_key, state_str);
206→                        let _ = writeln!(buf);
207→                        let _ = writeln!(buf, "{}", tack.text);
208→                        if let Some(ref direction) = tack.direction {
209→                            let _ = writeln!(buf);
210→                            let _ = writeln!(buf, "**Warrant:** {}", direction);
211→                        }
212→                        let _ = writeln!(buf);
213→                    }
214→                }
215→            }
216→        } else {
217→            // List view: numbered paces
218→            // If --remaining, output markdown format
219→            if args.remaining {
220→                let mut complete_count = 0;
221→                let mut abandoned_count = 0;
222→                let mut rough_count = 0;
223→                let mut bridled_count = 0;
224→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
225→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
226→
227→                for coronet_key in &heat.order {
228→                    if let Some(pace) = heat.paces.get(coronet_key) {
229→                        if let Some(tack) = pace.tacks.first() {
230→                            match tack.state {
231→                                PaceState::Complete => complete_count += 1,
232→                                PaceState::Abandoned => abandoned_count += 1,
233→                                PaceState::Rough => {
234→                                    rough_count += 1;
235→                                    remaining_paces.push((coronet_key, pace));
236→                                    if first_remaining_pace.is_none() {
237→                                        first_remaining_pace = Some((coronet_key, pace));
238→                                    }
239→                                }
240→                                PaceState::Bridled => {
241→                                    bridled_count += 1;
242→                                    remaining_paces.push((coronet_key, pace));
243→                                    if first_remaining_pace.is_none() {
244→                                        first_remaining_pace = Some((coronet_key, pace));
245→                                    }
246→                                }
247→                            }
248→                        }
249→                    }
250→                }
251→
252→                let status_str = match heat.status {
253→                    HeatStatus::Racing => "racing",
254→                    HeatStatus::Stabled => "stabled",
255→                    HeatStatus::Retired => "retired",
256→                };
257→
258→                let remaining_count = rough_count + bridled_count;
259→
260→                // Header line with heat info
261→                let _ = writeln!(buf, "Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
262→                let _ = writeln!(buf, "Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
263→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
264→                let _ = writeln!(buf);
265→
266→                // Table with remaining paces
267→                if !remaining_paces.is_empty() {
268→                    // Set up table with column definitions
269→                    let mut table = jjrp_Table::jjrp_new(vec![
270→                        jjrp_Column::new("No", jjrp_Align::Right),
271→                        jjrp_Column::new("State", jjrp_Align::Left),
272→                        jjrp_Column::new("Pace", jjrp_Align::Left),
273→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
274→                    ]);
275→
276→                    // Measure all rows to compute column widths
277→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
278→                        if let Some(tack) = pace.tacks.first() {
279→                            let state_str = zjjrpd_pace_state_str(&tack.state);
280→                            table.jjrp_measure(&[
281→                                &(idx + 1).to_string(),
282→                                state_str,
283→                                &tack.silks,
284→                                coronet_key,
285→                            ]);
286→                        }
287→                    }
288→
289→                    // Write header and separator
290→                    table.jjrp_write_header(&mut buf);
291→                    table.jjrp_write_separator(&mut buf);
292→
293→                    // Write data rows
294→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
295→                        if let Some(tack) = pace.tacks.first() {
296→                            let state_str = zjjrpd_pace_state_str(&tack.state);
297→                            table.jjrp_write_row(&mut buf, &[
298→                                &(idx + 1).to_string(),
299→                                state_str,
300→                                &tack.silks,
301→                                coronet_key,
302→                            ]);
303→                        }
304→                    }
305→                    let _ = writeln!(buf);
306→                }
307→
308→                // Next up callout
309→                if let Some((coronet_key, pace)) = first_remaining_pace {
310→                    if let Some(tack) = pace.tacks.first() {
311→                        let state_str = zjjrpd_pace_state_str(&tack.state);
312→                        let _ = writeln!(buf, "Next: {} ({}) [{}]", tack.silks, coronet_key, state_str);
313→                        jjbuf!(buf, "");
314→                        jjbuf!(buf, "Recommended: /jjc-heat-mount {}", heat_key);
315→                    }
316→                }
317→            } else {
318→                // Column-justified list view (all paces)
319→                // Set up table with column definitions
320→                let mut table = jjrp_Table::jjrp_new(vec![
321→                    jjrp_Column::new("No", jjrp_Align::Right),
322→                    jjrp_Column::new("State", jjrp_Align::Left),
323→                    jjrp_Column::new("Pace", jjrp_Align::Left),
324→                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
325→                ]);
326→
327→                // Measure all rows to compute column widths
328→                let mut num = 0;
329→                for coronet_key in &heat.order {
330→                    if let Some(pace) = heat.paces.get(coronet_key) {
331→                        if let Some(tack) = pace.tacks.first() {
332→                            num += 1;
333→                            let state_str = zjjrpd_pace_state_str(&tack.state);
334→                            table.jjrp_measure(&[
335→                                &num.to_string(),
336→                                state_str,
337→                                &tack.silks,
338→                                coronet_key,
339→                            ]);
340→                        }
341→                    }
342→                }
343→
344→                // Write header and separator
345→                table.jjrp_write_header(&mut buf);
346→                table.jjrp_write_separator(&mut buf);
347→
348→                // Write data rows
349→                let mut num = 0;
350→                for coronet_key in &heat.order {
351→                    if let Some(pace) = heat.paces.get(coronet_key) {
352→                        if let Some(tack) = pace.tacks.first() {
353→                            num += 1;
354→                            let state_str = zjjrpd_pace_state_str(&tack.state);
355→                            table.jjrp_write_row(&mut buf, &[
356→                                &num.to_string(),
357→                                state_str,
358→                                &tack.silks,
359→                                coronet_key,
360→                            ]);
361→                        }
362→                    }
363→                }
364→            }
365→        }
366→
367→        // Always show file-touch bitmap and commit swim lanes after pace listing
368→        jjrpd_write_file_bitmap(&mut buf, &firemark, heat);
369→        jjrpd_write_commit_swimlanes(&mut buf, &firemark, heat);
370→    } else {
371→        jjbuf!(buf, "jjx_show: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
372→        return (1, buf);
373→    }
374→
375→    (0, buf)
376→}
