378→/// Format the file-touch bitmap for a heat as a String.
379→///
380→/// Uses shared query routines from jjrq_query to get file touches,
381→/// then formats as a bitmap with columns per pace and rows per file,
382→/// grouped by identical touch patterns.
383→pub fn jjrpd_format_file_bitmap(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
384→    let touches = jjrq_file_touches_for_heat(firemark.jjrf_as_str())?;
385→
386→    // Build pace columns: only paces with commits, in heat order
387→    let mut pace_columns: Vec<(char, String, String)> = Vec::new();
388→    for coronet_key in &heat.order {
389→        if !touches.coronets_with_commits.contains(coronet_key) {
390→            continue;
391→        }
392→        if let Some(pace) = heat.paces.get(coronet_key) {
393→            if let Some(tack) = pace.tacks.first() {
394→                let raw = coronet_key.strip_prefix('₢').unwrap_or(coronet_key);
395→                if let Some(ch) = raw.chars().last() {
396→                    pace_columns.push((ch, coronet_key.clone(), tack.silks.clone()));
397→                }
398→            }
399→        }
400→    }
401→
402→    // Map coronet_display -> column index
403→    let mut coronet_to_col: BTreeMap<String, usize> = BTreeMap::new();
404→    for (idx, (_, coronet_display, _)) in pace_columns.iter().enumerate() {
405→        coronet_to_col.insert(coronet_display.clone(), idx);
406→    }
407→
408→    let total_cols = pace_columns.len();
409→
410→    // Build file -> touch vector from the shared query result
411→    let mut file_touches_map: BTreeMap<String, Vec<bool>> = BTreeMap::new();
412→
413→    for (coronet, files) in &touches.pace_files {
414→        if let Some(&col_idx) = coronet_to_col.get(coronet) {
415→            for filename in files {
416→                let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
417→                if col_idx < row.len() {
418→                    row[col_idx] = true;
419→                }
420→            }
421→        }
422→    }
423→
424→    let mut output = String::new();
425→
426→    if file_touches_map.is_empty() {
427→        writeln!(output, "File-touch bitmap: (no work file changes)").unwrap();
428→        return Ok(output);
429→    }
430→
431→    // Group files by identical touch pattern
432→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
433→    for (filename, pattern) in &file_touches_map {
434→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
435→    }
436→
437→    for files in pattern_groups.values_mut() {
438→        files.sort();
439→    }
440→
441→    // Header
442→    writeln!(output, "File-touch bitmap (x = pace commit touched file):").unwrap();
443→    writeln!(output).unwrap();
444→
445→    // Vertical legend
446→    for (i, (ch, _coronet, silks)) in pace_columns.iter().enumerate() {
447→        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
448→    }
449→    writeln!(output).unwrap();
450→
451→    // Column header line (terminal chars aligned with bitmap positions)
452→    let header_chars: Vec<char> = pace_columns.iter().map(|(ch, _, _)| *ch).collect();
453→    let header_line: String = header_chars.iter().collect();
454→    writeln!(output, "{}", header_line).unwrap();
455→
456→    // Sort patterns: more touches first, then lexicographic
457→    let mut sorted_patterns: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
458→    sorted_patterns.sort_by(|(pat_a, _), (pat_b, _)| {
459→        let count_a: usize = pat_a.iter().filter(|&&b| b).count();
460→        let count_b: usize = pat_b.iter().filter(|&&b| b).count();
461→        count_b.cmp(&count_a).then_with(|| pat_a.cmp(pat_b))
462→    });
463→
464→    for (pattern, files) in &sorted_patterns {
465→        let bitmap: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
466→        writeln!(output, "{} {}", bitmap, files.join(", ")).unwrap();
467→    }
468→
469→    Ok(output)
470→}
