472→/// Write the file-touch bitmap for a heat to a buffer.
473→pub(crate) fn jjrpd_write_file_bitmap(buf: &mut String, firemark: &Firemark, heat: &Heat) {
474→    match jjrpd_format_file_bitmap(firemark, heat) {
475→        Ok(output) => { let _ = write!(buf, "{}", output); }
476→        Err(e) => jjbuf!(buf, "jjx_show: error getting file touches: {}", e),
477→    }
478→}
