490→/// Resolve the default heat (first racing heat) when no target is specified
491→pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
492→    for (heat_key, heat) in &gallops.heats {
493→        if heat.status == HeatStatus::Racing {
494→            return Ok(heat_key.clone());
495→        }
496→    }
497→    Err("No racing heats found".to_string())
