500→/// Encode a column index as a dense character: 1-9 then a-z then A-Z (61 max)
501→fn zjjrpd_commit_index_char(index: usize) -> Option<char> {
502→    match index {
503→        0..=8 => Some((b'1' + index as u8) as char),
504→        9..=34 => Some((b'a' + (index - 9) as u8) as char),
505→        35..=60 => Some((b'A' + (index - 35) as u8) as char),
506→        _ => None,
507→    }
508→}
509→
510→/// Format commit swim lanes for a heat as a String: paces × commits matrix.
511→///
512→/// Shows when work happened on each pace and how work interleaved.
513→pub fn jjrpd_format_commit_swimlanes(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
514→    let rein_args = jjrs_ReinArgs {
515→        firemark: firemark.jjrf_as_str().to_string(),
516→        limit: 10000,
517→    };
518→
519→    let entries = jjrs_get_entries(&rein_args)?;
520→
521→    if entries.is_empty() {
522→        return Ok(String::new());
523→    }
524→
525→    // Entries are newest-first; truncate to 35 most recent, then reverse for chronological
526→    let total_commits = entries.len();
527→    let max_commits: usize = 35;
528→    let truncated = total_commits > max_commits;
529→    let display_entries: Vec<&jjrs_SteeplechaseEntry> = entries
530→        .iter()
531→        .take(max_commits)
532→        .collect::<Vec<_>>()
533→        .into_iter()
534→        .rev()
535→        .collect();
536→
537→    // Build pace rows: ordered by first chronological appearance
538→    let mut pace_order: Vec<(String, char, String)> = Vec::new(); // (coronet_display, term_char, silks)
539→    let mut pace_index: BTreeMap<String, usize> = BTreeMap::new();
540→
541→    for entry in &display_entries {
542→        if let Some(ref coronet) = entry.coronet {
543→            if !pace_index.contains_key(coronet) {
544→                let idx = pace_order.len();
545→                let raw = coronet.strip_prefix('₢').unwrap_or(coronet);
546→                let ch = raw.chars().last().unwrap_or('?');
547→                let silks = heat.paces.get(coronet)
548→                    .and_then(|p| p.tacks.first())
549→                    .map(|t| t.silks.clone())
550→                    .unwrap_or_else(|| "unknown".to_string());
551→                pace_index.insert(coronet.clone(), idx);
552→                pace_order.push((coronet.clone(), ch, silks));
553→            }
554→        }
555→        // heat-level entries (no coronet) are intentionally excluded from swim lanes
556→    }
557→
558→    let total_rows = pace_order.len();
559→
560→    if total_rows == 0 {
561→        return Ok(String::new());
562→    }
563→
564→    // Build bitmap: rows × columns
565→    let num_cols = display_entries.len();
566→    let mut bitmap: Vec<Vec<bool>> = vec![vec![false; num_cols]; total_rows];
567→    let mut row_commit_counts: Vec<usize> = vec![0; total_rows];
568→
569→    for (col, entry) in display_entries.iter().enumerate() {
570→        if let Some(ref coronet) = entry.coronet {
571→            if let Some(&row) = pace_index.get(coronet) {
572→                bitmap[row][col] = true;
573→                row_commit_counts[row] += 1;
574→            }
575→        }
576→        // heat-level entries (no coronet) are intentionally excluded from swim lanes
577→    }
578→
579→    let mut output = String::new();
580→
581→    writeln!(output).unwrap();
582→    writeln!(output, "Commit swim lanes (x = commit affiliated with pace):").unwrap();
583→    writeln!(output).unwrap();
584→
585→    if truncated {
586→        writeln!(output, "(showing last {} of {} commits)", max_commits, total_commits).unwrap();
587→        writeln!(output).unwrap();
588→    }
589→
590→    // Vertical legend
591→    for (i, (_, ch, silks)) in pace_order.iter().enumerate() {
592→        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
593→    }
594→    writeln!(output).unwrap();
595→
596→    // Column header line
597→    let header: String = (0..num_cols).filter_map(zjjrpd_commit_index_char).collect();
598→    writeln!(output, "{}", header).unwrap();
599→
600→    // Bitmap rows
601→    for row in 0..total_rows {
602→        let bits: String = bitmap[row].iter().map(|&b| if b { 'x' } else { '·' }).collect();
603→        let (term_char, count) = (pace_order[row].1, row_commit_counts[row]);
604→        writeln!(output, "{}  {}  {}c", bits, term_char, count).unwrap();
605→    }
606→
607→    Ok(output)
608→}
