610→/// Write commit swim lanes for a heat to a buffer.
611→pub(crate) fn jjrpd_write_commit_swimlanes(buf: &mut String, firemark: &Firemark, heat: &Heat) {
612→    match jjrpd_format_commit_swimlanes(firemark, heat) {
613→        Ok(output) => { let _ = write!(buf, "{}", output); }
614→        Err(e) => jjbuf!(buf, "jjx_show: error getting steeplechase entries: {}", e),
615→    }
