617→
618→/// Write files-per-commit bitmap for a single pace to a buffer.
619→///
620→/// Shows which files each commit in this pace touched.
621→/// Called after tack history in pace parade.
622→fn zjjrpd_write_pace_commits(buf: &mut String, firemark: &Firemark, coronet_key: &str) {
623→    let rein_args = jjrs_ReinArgs {
624→        firemark: firemark.jjrf_as_str().to_string(),
625→        limit: 10000,
626→    };
627→
628→    let entries = match jjrs_get_entries(&rein_args) {
629→        Ok(e) => e,
630→        Err(e) => {
631→            jjbuf!(buf, "jjx_show: error getting steeplechase entries: {}", e);
632→            return;
633→        }
634→    };
635→
636→    // Filter by coronet, then reverse for chronological order
637→    let pace_entries: Vec<&jjrs_SteeplechaseEntry> = entries
638→        .iter()
639→        .filter(|e| e.coronet.as_deref() == Some(coronet_key))
640→        .collect::<Vec<_>>()
641→        .into_iter()
642→        .rev()
643→        .collect();
644→
645→    if pace_entries.is_empty() {
646→        return;
647→    }
648→
649→    // Get files for each commit
650→    let num_commits = pace_entries.len();
651→    let mut file_touches: BTreeMap<String, Vec<bool>> = BTreeMap::new();
652→
653→    for (col, entry) in pace_entries.iter().enumerate() {
654→        let files = zjjrq_files_for_commit(&entry.commit);
655→        for path in files {
656→            if zjjrq_is_infra_file(&path) {
657→                continue;
658→            }
659→            let bare = zjjrq_bare_filename(&path);
660→            let row = file_touches.entry(bare).or_insert_with(|| vec![false; num_commits]);
661→            row[col] = true;
662→        }
663→    }
664→
665→    if file_touches.is_empty() {
666→        let _ = writeln!(buf);
667→        let _ = writeln!(buf, "Pace commits: (no project file commits)");
668→        return;
669→    }
670→
671→    let _ = writeln!(buf);
672→    let _ = writeln!(buf, "Pace commits (x = commit touched file):");
673→    let _ = writeln!(buf);
674→
675→    // Legend: commit index char, SHA, subject
676→    for (i, entry) in pace_entries.iter().enumerate() {
677→        let ch = zjjrpd_commit_index_char(i).unwrap_or('?');
678→        let _ = writeln!(buf, "  {} {}  {}", ch, entry.commit, entry.subject);
679→    }
680→    let _ = writeln!(buf);
681→
682→    // Column header line
683→    let header: String = (0..num_commits).filter_map(zjjrpd_commit_index_char).collect();
684→    let _ = writeln!(buf, "{}", header);
685→
686→    // Group by identical touch pattern
687→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
688→    for (filename, pattern) in &file_touches {
689→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
690→    }
691→    for files in pattern_groups.values_mut() {
692→        files.sort();
693→    }
694→
695→    // Sort: more touches first, then lexicographic
696→    let mut sorted: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
697→    sorted.sort_by(|(a, _), (b, _)| {
698→        let ca: usize = a.iter().filter(|&&v| v).count();
699→        let cb: usize = b.iter().filter(|&&v| v).count();
700→        cb.cmp(&ca).then_with(|| a.cmp(b))
701→    });
702→
703→    for (pattern, files) in &sorted {
704→        let bits: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
705→        let _ = writeln!(buf, "{} {}", bits, files.join(", "));
706→    }
707→}
