  5→//! jjx_retire command - Extract complete Heat data for archival trophy
  6→//!
  7→//! Handles retire operation: write trophy, remove from gallops, delete paddock, commit.
  8→//! Fails fast if gallops file has uncommitted changes.
  9→
 10→use std::path::{Path, PathBuf};
 11→
 12→use vvc::{vvco_out, vvco_err, vvco_Output};
 13→
 14→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 15→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_RetireArgs as LibRetireArgs};
 16→use crate::jjrs_steeplechase::{jjrs_ReinArgs as ReinArgs, jjrs_get_entries as get_entries};
 17→use crate::jjrc_core::jjrc_timestamp_date;
 18→use crate::jjrn_notch::{jjrn_format_heat_message, jjrn_HeatAction};
 19→
 20→/// Arguments for jjx_retire command
 21→#[derive(clap::Args, Debug)]
 22→pub struct jjrrt_RetireArgs {
 23→    /// Path to the Gallops JSON file
 24→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 25→    pub file: PathBuf,
 26→
 27→    /// Target Heat identity (Firemark)
 28→    pub firemark: String,
 29→
 30→    /// Override size limit for commit guard (bytes)
 31→    #[arg(long)]
 32→    pub size_limit: Option<u64>,
 33→}
 34→
 35→/// Run the retire command
 36→pub fn jjrrt_run_retire(args: jjrrt_RetireArgs) -> (i32, String) {
 37→    let mut output = vvco_Output::buffer();
 38→
 39→    let firemark = match Firemark::jjrf_parse(&args.firemark) {
 40→        Ok(fm) => fm,
 41→        Err(e) => {
 42→            vvco_err!(output, "jjx_retire: error: {}", e);
 43→            return (1, output.vvco_finish());
 44→        }
 45→    };
 46→
 47→    // Load gallops
 48→    let gallops = match Gallops::jjrg_load(&args.file) {
 49→        Ok(g) => g,
 50→        Err(e) => {
 51→            vvco_err!(output, "jjx_retire: error loading Gallops: {}", e);
 52→            return (1, output.vvco_finish());
 53→        }
 54→    };
 55→
 56→    // Get steeplechase entries (filtered by firemark identity)
 57→    let rein_args = ReinArgs {
 58→        firemark: args.firemark.clone(),
 59→        limit: 1000,
 60→    };
 61→    let steeplechase = match get_entries(&rein_args) {
 62→        Ok(entries) => entries,
 63→        Err(e) => {
 64→            vvco_err!(output, "jjx_retire: warning: could not get steeplechase: {}", e);
 65→            Vec::new()
 66→        }
 67→    };
 68→
 69→    // Compute base path from gallops file
 70→    let base_path = args.file.parent()
 71→        .and_then(|p| p.parent())
 72→        .and_then(|p| p.parent())
 73→        .unwrap_or(Path::new("."));
 74→
 75→    // Fail-fast guard: reject if gallops file has uncommitted changes
 76→    let gallops_rel = args.file.to_string_lossy().to_string();
 77→    let status_output = match vvc::vvce_git_command(&["status", "--porcelain", "--", &gallops_rel])
 78→        .output()
 79→    {
 80→        Ok(o) => o,
 81→        Err(e) => {
 82→            vvco_err!(output, "jjx_retire: error: failed to run git status: {}", e);
 83→            return (1, output.vvco_finish());
 84→        }
 85→    };
 86→    if !status_output.status.success() {
 87→        vvco_err!(output, "jjx_retire: error: git status failed");
 88→        return (1, output.vvco_finish());
 89→    }
 90→    let status_text = String::from_utf8_lossy(&status_output.stdout);
 91→    if !status_text.trim().is_empty() {
 92→        vvco_err!(output, "jjx_retire: error: gallops file has uncommitted changes — commit or discard first");
 93→        return (1, output.vvco_finish());
 94→    }
 95→
 96→    let mut gallops = gallops;
 97→
 98→    // Acquire lock FIRST
 99→    let lock = match vvc::vvcc_CommitLock::vvcc_acquire() {
100→        Ok(l) => l,
101→        Err(e) => {
102→            vvco_err!(output, "jjx_retire: error: {}", e);
103→            return (1, output.vvco_finish());
104→        }
105→    };
106→
107→    // Execute retire
108→    let retire_args = LibRetireArgs {
109→        firemark: args.firemark.clone(),
110→        today: jjrc_timestamp_date(),
111→    };
112→
113→    let result = match gallops.jjrg_retire(retire_args, base_path, &steeplechase) {
114→        Ok(r) => r,
115→        Err(e) => {
116→            vvco_err!(output, "jjx_retire: error: {}", e);
117→            return (1, output.vvco_finish());
118→        }
119→    };
120→
121→    // Save gallops
122→    if let Err(e) = gallops.jjrg_save(&args.file) {
123→        vvco_err!(output, "jjx_retire: error saving Gallops: {}", e);
124→        return (1, output.vvco_finish());
125→    }
126→
127→    // Commit using vvcm_commit with explicit file list
128→    // Files: gallops.json, trophy file (created), paddock file (deleted - git add handles this)
129→    let gallops_path = args.file.to_string_lossy().to_string();
130→    let effective_size_limit = args.size_limit.unwrap_or(200000);
131→    let commit_args = vvc::vvcm_CommitArgs {
132→        files: vec![
133→            gallops_path,
134→            result.trophy_path.clone(),
135→            result.paddock_path.clone(),
136→        ],
137→        message: jjrn_format_heat_message(&firemark, jjrn_HeatAction::Retire, &result.silks),
138→        size_limit: effective_size_limit,
139→        warn_limit: effective_size_limit / 2,
140→    };
141→
142→    match vvc::machine_commit(&lock, &commit_args, &mut output) {
143→        Ok(hash) => {
144→            vvco_out!(output, "jjx_retire: committed {}", &hash[..8]);
145→        }
146→        Err(e) => {
147→            vvco_err!(output, "jjx_retire: error: commit failed: {}", e);
148→            // Rollback: restore gallops and paddock from HEAD, remove trophy
149→            let gp = args.file.to_string_lossy().to_string();
150→            let _ = vvc::vvce_git_command(&["checkout", "HEAD", "--", &gp, &result.paddock_path])
151→                .status();
152→            let _ = vvc::vvce_git_command(&["rm", "-f", "--cached", &result.trophy_path])
153→                .status();
154→            let _ = std::fs::remove_file(&result.trophy_path);
155→            vvco_err!(output, "jjx_retire: rolled back file changes");
156→            vvco_err!(output, "jjx_retire: retry with --size-limit <bytes> to override guard");
157→            return (1, output.vvco_finish());
158→        }
159→    }
160→
161→    // Output result
162→    vvco_out!(output, "trophy: {}", result.trophy_path);
163→    vvco_out!(output, "Heat {} retired successfully", result.firemark);
164→
165→    (0, output.vvco_finish())
166→    // lock released here
167→}
