  5→//! Parade command - Display comprehensive Heat status for project review
  6→//!
  7→//! Implements both heat view (Firemark) and pace view (Coronet).
  8→
  9→use crate::jjrf_favor::jjrf_Firemark as Firemark;
 10→use crate::jjrf_favor::jjrf_Coronet as Coronet;
 11→use crate::jjrg_gallops::{jjrg_Gallops as Gallops, jjrg_Heat as Heat, jjrg_HeatStatus as HeatStatus, jjrg_PaceState as PaceState};
 12→use crate::jjrp_print::{jjrp_Table, jjrp_Column, jjrp_Align};
 13→use crate::jjrq_query::{jjrq_files_for_pace, jjrq_file_touches_for_heat, zjjrq_files_for_commit, zjjrq_bare_filename, zjjrq_is_infra_file};
 14→use crate::jjrs_steeplechase::{jjrs_ReinArgs, jjrs_get_entries, jjrs_SteeplechaseEntry};
 15→use std::collections::BTreeMap;
 16→use std::fmt::Write;
 17→use std::fs;
 18→
 19→use vvc::{vvco_out, vvco_err, vvco_Output};
 20→
 21→/// Arguments for jjx_show command
 22→#[derive(clap::Args, Debug)]
 23→pub struct jjrpd_ParadeArgs {
 24→    /// Path to the Gallops JSON file
 25→    #[arg(long, short = 'f', default_value = ".claude/jjm/jjg_gallops.json")]
 26→    pub file: std::path::PathBuf,
 27→
 28→    /// Target: Firemark (heat view) or Coronet (pace view). If omitted, uses first racing heat.
 29→    pub target: Option<String>,
 30→
 31→    /// Show paddock and full dockets (heat mode only)
 32→    #[arg(long)]
 33→    pub detail: bool,
 34→
 35→    /// Show only remaining paces (exclude complete/abandoned)
 36→    #[arg(long)]
 37→    pub remaining: bool,
 38→}
 39→
 40→/// Run the show command - display comprehensive Heat status
 41→pub fn jjrpd_run_parade(args: jjrpd_ParadeArgs) -> (i32, String) {
 42→    let mut output = vvco_Output::buffer();
 43→    let gallops = match Gallops::jjrg_load(&args.file) {
 44→        Ok(g) => g,
 45→        Err(e) => {
 46→            vvco_err!(output, "jjx_show: error: {}", e);
 47→            return (1, output.vvco_finish());
 48→        }
 49→    };
 50→
 51→    // Resolve target: use provided value or auto-select first racing heat
 52→    let target = match args.target {
 53→        Some(t) => t,
 54→        None => {
 55→            // Load gallops to resolve default heat
 56→            match zjjrpd_resolve_default_heat(&gallops) {
 57→                Ok(fm) => fm,
 58→                Err(e) => {
 59→                    vvco_err!(output, "jjx_show: error: {}", e);
 60→                    return (1, output.vvco_finish());
 61→                }
 62→            }
 63→        }
 64→    };
 65→
 66→    // Determine target type by length
 67→    let target_str = target.strip_prefix('₢').or_else(|| target.strip_prefix('₣')).unwrap_or(&target);
 68→
 69→    if target_str.len() == 5 {
 70→        // Coronet - pace view
 71→        let coronet = match Coronet::jjrf_parse(&target) {
 72→            Ok(c) => c,
 73→            Err(e) => {
 74→                vvco_err!(output, "jjx_show: error: {}", e);
 75→                return (1, output.vvco_finish());
 76→            }
 77→        };
 78→
 79→        // Extract parent firemark
 80→        let firemark = coronet.jjrf_parent_firemark();
 81→        let heat_key = firemark.jjrf_display();
 82→        let heat = match gallops.heats.get(&heat_key) {
 83→            Some(h) => h,
 84→            None => {
 85→                vvco_err!(output, "jjx_show: error: Heat '{}' not found", heat_key);
 86→                return (1, output.vvco_finish());
 87→            }
 88→        };
 89→
 90→        // Find pace
 91→        let coronet_key = coronet.jjrf_display();
 92→        let pace = match heat.paces.get(&coronet_key) {
 93→            Some(p) => p,
 94→            None => {
 95→                vvco_err!(output, "jjx_show: error: Pace '{}' not found in Heat '{}'", coronet_key, heat_key);
 96→                return (1, output.vvco_finish());
 97→            }
 98→        };
 99→
100→        // Display pace view
101→        if !pace.tacks.is_empty() {
102→            // Write header with current state from tacks[0]
103→            let current_tack = &pace.tacks[0];
104→            vvco_out!(output, "Pace: {} ({}) [{}]", current_tack.silks, coronet_key, zjjrpd_pace_state_str(&current_tack.state));
105→            vvco_out!(output, "Heat: {}", heat_key);
106→
107→            // Show work files touched by this pace's commits
108→            match jjrq_files_for_pace(firemark.jjrf_as_str(), &coronet_key) {
109→                Ok(files) if !files.is_empty() => {
110→                    vvco_out!(output, "Work files: {}", files.join(", "));
111→                }
112→                _ => {}
113→            }
114→            vvco_out!(output, "");
115→
116→            if args.detail {
117→                // Detail view: full tack history in reverse order (oldest first)
118→                for (index, tack) in pace.tacks.iter().rev().enumerate() {
119→                    let state_str = zjjrpd_pace_state_str(&tack.state);
120→                    let basis_str = if tack.basis == "0000000" {
121→                        "(no basis)".to_string()
122→                    } else {
123→                        tack.basis.clone()
124→                    };
125→
126→                    vvco_out!(output, "[{}] {} (basis: {})", index, state_str, basis_str);
127→                    vvco_out!(output, "    Silks: {}", tack.silks);
128→                    if let Some(ref direction) = tack.direction {
129→                        vvco_out!(output, "    Warrant: {}", direction);
130→                    }
131→                    vvco_out!(output, "");
132→                    // Indent docket text
133→                    for line in tack.text.lines() {
134→                        vvco_out!(output, "    {}", line);
135→                    }
136→                    vvco_out!(output, "");
137→                }
138→            } else {
139→                // Default view: latest tack docket only
140→                if let Some(ref direction) = current_tack.direction {
141→                    vvco_out!(output, "Warrant: {}", direction);
142→                    vvco_out!(output, "");
143→                }
144→                for line in current_tack.text.lines() {
145→                    vvco_out!(output, "{}", line);
146→                }
147→                vvco_out!(output, "");
148→            }
149→
150→            // Append files-per-commit bitmap
151→            zjjrpd_write_pace_commits(&mut output, &firemark, &coronet_key);
152→        }
153→    } else if target_str.len() == 2 {
154→        // Firemark - heat view
155→        let firemark = match Firemark::jjrf_parse(&target) {
156→            Ok(fm) => fm,
157→            Err(e) => {
158→                vvco_err!(output, "jjx_show: error: {}", e);
159→                return (1, output.vvco_finish());
160→            }
161→        };
162→
163→        let heat_key = firemark.jjrf_display();
164→        let heat = match gallops.heats.get(&heat_key) {
165→            Some(h) => h,
166→            None => {
167→                vvco_err!(output, "jjx_show: error: Heat '{}' not found", heat_key);
168→                return (1, output.vvco_finish());
169→            }
170→        };
171→
172→        if args.detail {
173→            // Detail view: paddock + all dockets
174→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
175→                Ok(content) => content,
176→                Err(e) => {
177→                    vvco_err!(output, "jjx_show: error reading paddock file '{}': {}", heat.paddock_file, e);
178→                    return (1, output.vvco_finish());
179→                }
180→            };
181→
182→            let status_str = match heat.status {
183→                HeatStatus::Racing => "racing",
184→                HeatStatus::Stabled => "stabled",
185→                HeatStatus::Retired => "retired",
186→            };
187→
188→            vvco_out!(output, "Heat: {} ({})", heat.silks, heat_key);
189→            vvco_out!(output, "Status: {}", status_str);
190→            vvco_out!(output, "Created: {}", heat.creation_time);
191→            vvco_out!(output, "");
192→            vvco_out!(output, "## Paddock");
193→            vvco_out!(output, "");
194→            vvco_out!(output, "{}", paddock_content);
195→            vvco_out!(output, "");
196→            vvco_out!(output, "## Paces");
197→            vvco_out!(output, "");
198→
199→            for coronet_key in &heat.order {
200→                if let Some(pace) = heat.paces.get(coronet_key) {
201→                    if let Some(tack) = pace.tacks.first() {
202→                        // Skip complete/abandoned if --remaining
203→                        if args.remaining && (tack.state == PaceState::Complete || tack.state == PaceState::Abandoned) {
204→                            continue;
205→                        }
206→                        let state_str = zjjrpd_pace_state_str(&tack.state);
207→                        vvco_out!(output, "### {} ({}) [{}]", tack.silks, coronet_key, state_str);
208→                        vvco_out!(output, "");
209→                        vvco_out!(output, "{}", tack.text);
210→                        if let Some(ref direction) = tack.direction {
211→                            vvco_out!(output, "");
212→                            vvco_out!(output, "**Warrant:** {}", direction);
213→                        }
214→                        vvco_out!(output, "");
215→                    }
216→                }
217→            }
218→        } else {
219→            // List view: numbered paces
220→            // If --remaining, output markdown format
221→            if args.remaining {
222→                let mut complete_count = 0;
223→                let mut abandoned_count = 0;
224→                let mut rough_count = 0;
225→                let mut bridled_count = 0;
226→                let mut remaining_paces: Vec<(&String, &crate::jjrg_gallops::jjrg_Pace)> = Vec::new();
227→                let mut first_remaining_pace: Option<(&String, &crate::jjrg_gallops::jjrg_Pace)> = None;
228→
229→                for coronet_key in &heat.order {
230→                    if let Some(pace) = heat.paces.get(coronet_key) {
231→                        if let Some(tack) = pace.tacks.first() {
232→                            match tack.state {
233→                                PaceState::Complete => complete_count += 1,
234→                                PaceState::Abandoned => abandoned_count += 1,
235→                                PaceState::Rough => {
236→                                    rough_count += 1;
237→                                    remaining_paces.push((coronet_key, pace));
238→                                    if first_remaining_pace.is_none() {
239→                                        first_remaining_pace = Some((coronet_key, pace));
240→                                    }
241→                                }
242→                                PaceState::Bridled => {
243→                                    bridled_count += 1;
244→                                    remaining_paces.push((coronet_key, pace));
245→                                    if first_remaining_pace.is_none() {
246→                                        first_remaining_pace = Some((coronet_key, pace));
247→                                    }
248→                                }
249→                            }
250→                        }
251→                    }
252→                }
253→
254→                let status_str = match heat.status {
255→                    HeatStatus::Racing => "racing",
256→                    HeatStatus::Stabled => "stabled",
257→                    HeatStatus::Retired => "retired",
258→                };
259→
260→                let remaining_count = rough_count + bridled_count;
261→
262→                // Header line with heat info
263→                vvco_out!(output, "Heat: {} ({}) [{}]", heat.silks, heat_key, status_str);
264→                vvco_out!(output, "Progress: {} complete | {} abandoned | {} remaining ({} rough, {} bridled)",
265→                    complete_count, abandoned_count, remaining_count, rough_count, bridled_count);
266→                vvco_out!(output, "");
267→
268→                // Table with remaining paces
269→                if !remaining_paces.is_empty() {
270→                    // Set up table with column definitions
271→                    let mut table = jjrp_Table::jjrp_new(vec![
272→                        jjrp_Column::new("No", jjrp_Align::Right),
273→                        jjrp_Column::new("State", jjrp_Align::Left),
274→                        jjrp_Column::new("Pace", jjrp_Align::Left),
275→                        jjrp_Column::new("₢Coronet", jjrp_Align::Left),
276→                    ]);
277→
278→                    // Measure all rows to compute column widths
279→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
280→                        if let Some(tack) = pace.tacks.first() {
281→                            let state_str = zjjrpd_pace_state_str(&tack.state);
282→                            table.jjrp_measure(&[
283→                                &(idx + 1).to_string(),
284→                                state_str,
285→                                &tack.silks,
286→                                coronet_key,
287→                            ]);
288→                        }
289→                    }
290→
291→                    // Write header and separator
292→                    table.jjrp_write_header(&mut output);
293→                    table.jjrp_write_separator(&mut output);
294→
295→                    // Write data rows
296→                    for (idx, (coronet_key, pace)) in remaining_paces.iter().enumerate() {
297→                        if let Some(tack) = pace.tacks.first() {
298→                            let state_str = zjjrpd_pace_state_str(&tack.state);
299→                            table.jjrp_write_row(&mut output, &[
300→                                &(idx + 1).to_string(),
301→                                state_str,
302→                                &tack.silks,
303→                                coronet_key,
304→                            ]);
305→                        }
306→                    }
307→                    vvco_out!(output, "");
308→                }
309→
310→                // Next up callout
311→                if let Some((coronet_key, pace)) = first_remaining_pace {
312→                    if let Some(tack) = pace.tacks.first() {
313→                        let state_str = zjjrpd_pace_state_str(&tack.state);
314→                        vvco_out!(output, "Next: {} ({}) [{}]", tack.silks, coronet_key, state_str);
315→                        vvco_out!(output, "");
316→                        vvco_out!(output, "Recommended: /jjc-heat-mount {}", heat_key);
317→                    }
318→                }
319→            } else {
320→                // Column-justified list view (all paces)
321→                // Set up table with column definitions
322→                let mut table = jjrp_Table::jjrp_new(vec![
323→                    jjrp_Column::new("No", jjrp_Align::Right),
324→                    jjrp_Column::new("State", jjrp_Align::Left),
325→                    jjrp_Column::new("Pace", jjrp_Align::Left),
326→                    jjrp_Column::new("₢Coronet", jjrp_Align::Left),
327→                ]);
328→
329→                // Measure all rows to compute column widths
330→                let mut num = 0;
331→                for coronet_key in &heat.order {
332→                    if let Some(pace) = heat.paces.get(coronet_key) {
333→                        if let Some(tack) = pace.tacks.first() {
334→                            num += 1;
335→                            let state_str = zjjrpd_pace_state_str(&tack.state);
336→                            table.jjrp_measure(&[
337→                                &num.to_string(),
338→                                state_str,
339→                                &tack.silks,
340→                                coronet_key,
341→                            ]);
342→                        }
343→                    }
344→                }
345→
346→                // Write header and separator
347→                table.jjrp_write_header(&mut output);
348→                table.jjrp_write_separator(&mut output);
349→
350→                // Write data rows
351→                let mut num = 0;
352→                for coronet_key in &heat.order {
353→                    if let Some(pace) = heat.paces.get(coronet_key) {
354→                        if let Some(tack) = pace.tacks.first() {
355→                            num += 1;
356→                            let state_str = zjjrpd_pace_state_str(&tack.state);
357→                            table.jjrp_write_row(&mut output, &[
358→                                &num.to_string(),
359→                                state_str,
360→                                &tack.silks,
361→                                coronet_key,
362→                            ]);
363→                        }
364→                    }
365→                }
366→            }
367→        }
368→
369→        // Always show file-touch bitmap and commit swim lanes after pace listing
370→        jjrpd_write_file_bitmap(&mut output, &firemark, heat);
371→        jjrpd_write_commit_swimlanes(&mut output, &firemark, heat);
372→    } else {
373→        vvco_err!(output, "jjx_show: error: target must be Firemark (2 chars) or Coronet (5 chars), got {} chars", target_str.len());
374→        return (1, output.vvco_finish());
375→    }
376→
377→    (0, output.vvco_finish())
378→}
