380→/// Format the file-touch bitmap for a heat as a String.
381→///
382→/// Uses shared query routines from jjrq_query to get file touches,
383→/// then formats as a bitmap with columns per pace and rows per file,
384→/// grouped by identical touch patterns.
385→pub fn jjrpd_format_file_bitmap(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
386→    let touches = jjrq_file_touches_for_heat(firemark.jjrf_as_str())?;
387→
388→    // Build pace columns: only paces with commits, in heat order
389→    let mut pace_columns: Vec<(char, String, String)> = Vec::new();
390→    for coronet_key in &heat.order {
391→        if !touches.coronets_with_commits.contains(coronet_key) {
392→            continue;
393→        }
394→        if let Some(pace) = heat.paces.get(coronet_key) {
395→            if let Some(tack) = pace.tacks.first() {
396→                let raw = coronet_key.strip_prefix('₢').unwrap_or(coronet_key);
397→                if let Some(ch) = raw.chars().last() {
398→                    pace_columns.push((ch, coronet_key.clone(), tack.silks.clone()));
399→                }
400→            }
401→        }
402→    }
403→
404→    // Map coronet_display -> column index
405→    let mut coronet_to_col: BTreeMap<String, usize> = BTreeMap::new();
406→    for (idx, (_, coronet_display, _)) in pace_columns.iter().enumerate() {
407→        coronet_to_col.insert(coronet_display.clone(), idx);
408→    }
409→
410→    let total_cols = pace_columns.len();
411→
412→    // Build file -> touch vector from the shared query result
413→    let mut file_touches_map: BTreeMap<String, Vec<bool>> = BTreeMap::new();
414→
415→    for (coronet, files) in &touches.pace_files {
416→        if let Some(&col_idx) = coronet_to_col.get(coronet) {
417→            for filename in files {
418→                let row = file_touches_map.entry(filename.clone()).or_insert_with(|| vec![false; total_cols]);
419→                if col_idx < row.len() {
420→                    row[col_idx] = true;
421→                }
422→            }
423→        }
424→    }
425→
426→    let mut output = String::new();
427→
428→    if file_touches_map.is_empty() {
429→        writeln!(output, "File-touch bitmap: (no work file changes)").unwrap();
430→        return Ok(output);
431→    }
432→
433→    // Group files by identical touch pattern
434→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
435→    for (filename, pattern) in &file_touches_map {
436→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
437→    }
438→
439→    for files in pattern_groups.values_mut() {
440→        files.sort();
441→    }
442→
443→    // Header
444→    writeln!(output, "File-touch bitmap (x = pace commit touched file):").unwrap();
445→    writeln!(output).unwrap();
446→
447→    // Vertical legend
448→    for (i, (ch, _coronet, silks)) in pace_columns.iter().enumerate() {
449→        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
450→    }
451→    writeln!(output).unwrap();
452→
453→    // Column header line (terminal chars aligned with bitmap positions)
454→    let header_chars: Vec<char> = pace_columns.iter().map(|(ch, _, _)| *ch).collect();
455→    let header_line: String = header_chars.iter().collect();
456→    writeln!(output, "{}", header_line).unwrap();
457→
458→    // Sort patterns: more touches first, then lexicographic
459→    let mut sorted_patterns: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
460→    sorted_patterns.sort_by(|(pat_a, _), (pat_b, _)| {
461→        let count_a: usize = pat_a.iter().filter(|&&b| b).count();
462→        let count_b: usize = pat_b.iter().filter(|&&b| b).count();
463→        count_b.cmp(&count_a).then_with(|| pat_a.cmp(pat_b))
464→    });
465→
466→    for (pattern, files) in &sorted_patterns {
467→        let bitmap: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
468→        writeln!(output, "{} {}", bitmap, files.join(", ")).unwrap();
469→    }
470→
471→    Ok(output)
472→}
473→
474→/// Write the file-touch bitmap for a heat to output.
475→pub(crate) fn jjrpd_write_file_bitmap(output: &mut vvco_Output, firemark: &Firemark, heat: &Heat) {
476→    match jjrpd_format_file_bitmap(firemark, heat) {
477→        Ok(text) => {
478→            for line in text.lines() {
479→                vvco_out!(output, "{}", line);
480→            }
481→        }
482→        Err(e) => vvco_err!(output, "jjx_show: error getting file touches: {}", e),
483→    }
484→}
