486→/// Helper to convert PaceState to display string
487→pub(crate) fn zjjrpd_pace_state_str(state: &PaceState) -> &'static str {
488→    match state {
489→        PaceState::Rough => "rough",
490→        PaceState::Bridled => "bridled",
491→        PaceState::Complete => "complete",
492→        PaceState::Abandoned => "abandoned",
