496→/// Resolve the default heat (first racing heat) when no target is specified
497→pub(crate) fn zjjrpd_resolve_default_heat(gallops: &Gallops) -> Result<String, String> {
498→    for (heat_key, heat) in &gallops.heats {
499→        if heat.status == HeatStatus::Racing {
500→            return Ok(heat_key.clone());
501→        }
502→    }
503→    Err("No racing heats found".to_string())
504→}
505→
506→/// Encode a column index as a dense character: 1-9 then a-z then A-Z (61 max)
507→fn zjjrpd_commit_index_char(index: usize) -> Option<char> {
508→    match index {
509→        0..=8 => Some((b'1' + index as u8) as char),
510→        9..=34 => Some((b'a' + (index - 9) as u8) as char),
511→        35..=60 => Some((b'A' + (index - 35) as u8) as char),
512→        _ => None,
513→    }
514→}
515→
516→/// Format commit swim lanes for a heat as a String: paces × commits matrix.
517→///
518→/// Shows when work happened on each pace and how work interleaved.
519→pub fn jjrpd_format_commit_swimlanes(firemark: &Firemark, heat: &Heat) -> Result<String, String> {
520→    let rein_args = jjrs_ReinArgs {
521→        firemark: firemark.jjrf_as_str().to_string(),
522→        limit: 10000,
523→    };
524→
525→    let entries = jjrs_get_entries(&rein_args)?;
526→
527→    if entries.is_empty() {
528→        return Ok(String::new());
529→    }
530→
531→    // Entries are newest-first; truncate to 35 most recent, then reverse for chronological
532→    let total_commits = entries.len();
533→    let max_commits: usize = 35;
534→    let truncated = total_commits > max_commits;
535→    let display_entries: Vec<&jjrs_SteeplechaseEntry> = entries
536→        .iter()
537→        .take(max_commits)
538→        .collect::<Vec<_>>()
539→        .into_iter()
540→        .rev()
541→        .collect();
542→
543→    // Build pace rows: ordered by first chronological appearance
544→    let mut pace_order: Vec<(String, char, String)> = Vec::new(); // (coronet_display, term_char, silks)
545→    let mut pace_index: BTreeMap<String, usize> = BTreeMap::new();
546→
547→    for entry in &display_entries {
548→        if let Some(ref coronet) = entry.coronet {
549→            if !pace_index.contains_key(coronet) {
550→                let idx = pace_order.len();
551→                let raw = coronet.strip_prefix('₢').unwrap_or(coronet);
552→                let ch = raw.chars().last().unwrap_or('?');
553→                let silks = heat.paces.get(coronet)
554→                    .and_then(|p| p.tacks.first())
555→                    .map(|t| t.silks.clone())
556→                    .unwrap_or_else(|| "unknown".to_string());
557→                pace_index.insert(coronet.clone(), idx);
558→                pace_order.push((coronet.clone(), ch, silks));
559→            }
560→        }
561→        // heat-level entries (no coronet) are intentionally excluded from swim lanes
562→    }
563→
564→    let total_rows = pace_order.len();
565→
566→    if total_rows == 0 {
567→        return Ok(String::new());
568→    }
569→
570→    // Build bitmap: rows × columns
571→    let num_cols = display_entries.len();
572→    let mut bitmap: Vec<Vec<bool>> = vec![vec![false; num_cols]; total_rows];
573→    let mut row_commit_counts: Vec<usize> = vec![0; total_rows];
574→
575→    for (col, entry) in display_entries.iter().enumerate() {
576→        if let Some(ref coronet) = entry.coronet {
577→            if let Some(&row) = pace_index.get(coronet) {
578→                bitmap[row][col] = true;
579→                row_commit_counts[row] += 1;
580→            }
581→        }
582→        // heat-level entries (no coronet) are intentionally excluded from swim lanes
583→    }
584→
585→    let mut output = String::new();
586→
587→    writeln!(output).unwrap();
588→    writeln!(output, "Commit swim lanes (x = commit affiliated with pace):").unwrap();
589→    writeln!(output).unwrap();
590→
591→    if truncated {
592→        writeln!(output, "(showing last {} of {} commits)", max_commits, total_commits).unwrap();
593→        writeln!(output).unwrap();
594→    }
595→
596→    // Vertical legend
597→    for (i, (_, ch, silks)) in pace_order.iter().enumerate() {
598→        writeln!(output, "  {} {} {}", i + 1, ch, silks).unwrap();
599→    }
600→    writeln!(output).unwrap();
601→
602→    // Column header line
603→    let header: String = (0..num_cols).filter_map(zjjrpd_commit_index_char).collect();
604→    writeln!(output, "{}", header).unwrap();
605→
606→    // Bitmap rows
607→    for row in 0..total_rows {
608→        let bits: String = bitmap[row].iter().map(|&b| if b { 'x' } else { '·' }).collect();
609→        let (term_char, count) = (pace_order[row].1, row_commit_counts[row]);
610→        writeln!(output, "{}  {}  {}c", bits, term_char, count).unwrap();
611→    }
612→
613→    Ok(output)
614→}
615→
616→/// Write commit swim lanes for a heat to output.
617→pub(crate) fn jjrpd_write_commit_swimlanes(output: &mut vvco_Output, firemark: &Firemark, heat: &Heat) {
618→    match jjrpd_format_commit_swimlanes(firemark, heat) {
619→        Ok(text) => {
620→            for line in text.lines() {
621→                vvco_out!(output, "{}", line);
622→            }
623→        }
624→        Err(e) => vvco_err!(output, "jjx_show: error getting steeplechase entries: {}", e),
625→    }
626→}
627→
628→/// Write files-per-commit bitmap for a single pace to output.
629→///
630→/// Shows which files each commit in this pace touched.
631→/// Called after tack history in pace parade.
632→fn zjjrpd_write_pace_commits(output: &mut vvco_Output, firemark: &Firemark, coronet_key: &str) {
633→    let rein_args = jjrs_ReinArgs {
634→        firemark: firemark.jjrf_as_str().to_string(),
635→        limit: 10000,
636→    };
637→
638→    let entries = match jjrs_get_entries(&rein_args) {
639→        Ok(e) => e,
640→        Err(e) => {
641→            vvco_err!(output, "jjx_show: error getting steeplechase entries: {}", e);
642→            return;
643→        }
644→    };
645→
646→    // Filter by coronet, then reverse for chronological order
647→    let pace_entries: Vec<&jjrs_SteeplechaseEntry> = entries
648→        .iter()
649→        .filter(|e| e.coronet.as_deref() == Some(coronet_key))
650→        .collect::<Vec<_>>()
651→        .into_iter()
652→        .rev()
653→        .collect();
654→
655→    if pace_entries.is_empty() {
656→        return;
657→    }
658→
659→    // Get files for each commit
660→    let num_commits = pace_entries.len();
661→    let mut file_touches: BTreeMap<String, Vec<bool>> = BTreeMap::new();
662→
663→    for (col, entry) in pace_entries.iter().enumerate() {
664→        let files = zjjrq_files_for_commit(&entry.commit);
665→        for path in files {
666→            if zjjrq_is_infra_file(&path) {
667→                continue;
668→            }
669→            let bare = zjjrq_bare_filename(&path);
670→            let row = file_touches.entry(bare).or_insert_with(|| vec![false; num_commits]);
671→            row[col] = true;
672→        }
673→    }
674→
675→    if file_touches.is_empty() {
676→        vvco_out!(output, "");
677→        vvco_out!(output, "Pace commits: (no project file commits)");
678→        return;
679→    }
680→
681→    vvco_out!(output, "");
682→    vvco_out!(output, "Pace commits (x = commit touched file):");
683→    vvco_out!(output, "");
684→
685→    // Legend: commit index char, SHA, subject
686→    for (i, entry) in pace_entries.iter().enumerate() {
687→        let ch = zjjrpd_commit_index_char(i).unwrap_or('?');
688→        vvco_out!(output, "  {} {}  {}", ch, entry.commit, entry.subject);
689→    }
690→    vvco_out!(output, "");
691→
692→    // Column header line
693→    let header: String = (0..num_commits).filter_map(zjjrpd_commit_index_char).collect();
694→    vvco_out!(output, "{}", header);
695→
696→    // Group by identical touch pattern
697→    let mut pattern_groups: BTreeMap<Vec<bool>, Vec<String>> = BTreeMap::new();
698→    for (filename, pattern) in &file_touches {
699→        pattern_groups.entry(pattern.clone()).or_default().push(filename.clone());
700→    }
701→    for files in pattern_groups.values_mut() {
702→        files.sort();
703→    }
704→
705→    // Sort: more touches first, then lexicographic
706→    let mut sorted: Vec<(Vec<bool>, Vec<String>)> = pattern_groups.into_iter().collect();
707→    sorted.sort_by(|(a, _), (b, _)| {
708→        let ca: usize = a.iter().filter(|&&v| v).count();
709→        let cb: usize = b.iter().filter(|&&v| v).count();
710→        cb.cmp(&ca).then_with(|| a.cmp(b))
711→    });
712→
713→    for (pattern, files) in &sorted {
714→        let bits: String = pattern.iter().map(|&b| if b { 'x' } else { '·' }).collect();
715→        vvco_out!(output, "{} {}", bits, files.join(", "));
716→    }
717→}
718→
